// ----------------------------------
// GET INPUT ITEMS
// ----------------------------------
const items = $input.all();

// ----------------------------------
// PLATFORM NORMALIZER
// ----------------------------------
function normalizePlatforms(input) {
  if (!input) return "";

  const platformMap = {
    FB: ["facebook", "fb", "facebok", "fab", "meta"],
    IG: ["instagram", "insta", "ig", "instgram", "instra"],
    YOU: ["youtube", "yt", "youtub", "youtbe", "you"],
    LIN: ["linkedin", "linkdin", "linked", "ln"]
  };

  const order = ["FB", "IG", "YOU", "LIN"];

  const parts = input
    .toString()
    .toLowerCase()
    .split(/[\/,|&+\-]/);

  const detected = new Set();

  for (const part of parts) {
    const cleaned = part.replace(/[^a-z]/g, "");
    for (const [code, variants] of Object.entries(platformMap)) {
      if (variants.some(v => cleaned.includes(v))) {
        detected.add(code);
      }
    }
  }

  return order.filter(p => detected.has(p)).join("/");
}

// ----------------------------------
// STORY DETECTOR (FORMAT + PLATFORM)
// ----------------------------------
function isStory(input) {
  if (!input) return false;

  const cleaned = input
    .toString()
    .toLowerCase()
    .replace(/[^a-z]/g, "");

  return [
    "story",
    "stories",
    "instastory",
    "igstory",
    "instagramstory",
    "fbstory",
    "facebookstory",
    "status"
  ].some(v => cleaned.includes(v));
}

// ----------------------------------
// FORMAT NORMALIZER
// ----------------------------------
function normalizeFormat(formatInput, platformInput) {
  // 🔥 Story can be in Platform OR Format
  if (isStory(formatInput) || isStory(platformInput)) {
    return "STORIES";
  }

  const cleaned = (formatInput || "")
    .toString()
    .toLowerCase()
    .replace(/[^a-z]/g, "");

  if (["reel", "reels", "video", "vedio"].some(v => cleaned.includes(v)))
    return "REEL";

  if (["carousel", "carousal", "carausel", "slider", "slides"].some(v => cleaned.includes(v)))
    return "CAROUSEL";

  if (["image", "images", "photo", "photos", "pic", "picture"].some(v => cleaned.includes(v)))
    return "IMAGE";

  return "UNKNOWN";
}

// ----------------------------------
// FINAL ROUTING LOGIC
// ----------------------------------
return items.map(item => {
  const data = item.json;

  const platformRaw = data.Platform || data.platform || "";
  const formatRaw = data.Format || data.format || "";

  const formatCode = normalizeFormat(formatRaw, platformRaw);

  let platformCode;

  // 🔥 MASTER RULE
  // If STORIES detected anywhere → Instagram switch first
  if (formatCode === "STORIES") {
    platformCode = "IG";
  } else {
    platformCode = normalizePlatforms(platformRaw);
  }

  return {
    json: {
      ...data,
      platform_raw: platformRaw,
      platform_code: platformCode,
      format_raw: formatRaw,
      format_code: formatCode
    }
  };
});

function getNowIST() {
  return new Date(
    new Date().toLocaleString("en-US", { timeZone: "Asia/Kolkata" })
  );
}

const nowIST = getNowIST();
const todayIST = nowIST.toISOString().slice(0, 10); // YYYY-MM-DD

const output = [];

for (const item of items) {
  const data = item.json;

  const scheduledDT = data.ist_datetime; // ✅ CORRECT FIELD

  // Safety check
  if (!scheduledDT) continue;

  const scheduledDate = new Date(scheduledDT.replace(" ", "T"));
  const scheduledDateOnly = data.ist_date_only;

  // ❌ Drop if not today
  if (scheduledDateOnly !== todayIST) continue;

  // ❌ Drop if time is still in the future
  if (scheduledDate.getTime() > nowIST.getTime()) continue;

  // ✅ KEEP: time already passed
  output.push({
    json: {
      ...data,
      publish_now: true,
      reason: "Scheduled time already passed (IST)",
      now_ist: nowIST.toLocaleString("en-IN", { timeZone: "Asia/Kolkata" })
    }
  });
}

return output;

// =============================
// HELPERS
// =============================
const MONTHS = {
  jan: 0, feb: 1, mar: 2, apr: 3, may: 4, jun: 5,
  jul: 6, aug: 7, sep: 8, oct: 9, nov: 10, dec: 11
};

function parseCustomDate(raw) {
  // Normalize dash and spaces
  const cleaned = raw
    .replace(/–/g, "-")
    .replace(/\s+/g, " ")
    .trim();

  // Expected: DD Mon YYYY - HH:MM AM/PM
  const match = cleaned.match(
    /(\d{1,2}) (\w{3}) (\d{4}) - (\d{1,2}):(\d{2}) (AM|PM)/i
  );

  if (!match) return null;

  let [, day, mon, year, hour, min, meridian] = match;

  day = Number(day);
  year = Number(year);
  hour = Number(hour);
  min = Number(min);

  const monthIndex = MONTHS[mon.toLowerCase()];
  if (monthIndex === undefined) return null;

  // Convert to 24h
  if (meridian.toUpperCase() === "PM" && hour !== 12) hour += 12;
  if (meridian.toUpperCase() === "AM" && hour === 12) hour = 0;

  // Create IST date directly
  return new Date(year, monthIndex, day, hour, min, 0);
}

function formatDate(d) {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}

function formatTime(d) {
  return `${String(d.getHours()).padStart(2, "0")}:${String(d.getMinutes()).padStart(2, "0")}:00`;
}

// =============================
// PROCESS ITEMS
// =============================
const results = [];

for (const item of items) {
  const data = item.json;
  const raw = data["Date & Time (IST)"];

  if (!raw) {
    results.push({ json: { ...data, error: "NO_DATE_FOUND" } });
    continue;
  }

  const parsed = parseCustomDate(raw);

  if (!parsed) {
    results.push({
      json: {
        ...data,
        error: "UNSUPPORTED_DATE_FORMAT",
        original_value: raw
      }
    });
    continue;
  }

  results.push({
    json: {
      ...data,
      ist_date_only: formatDate(parsed),
      ist_time_only: formatTime(parsed),
      ist_datetime: `${formatDate(parsed)} ${formatTime(parsed)}`,
      converted_ok: true
    }
  });
}

return results;

