// Clone full incoming JSON
let output = { ...$json };

// Fix Captions (case-sensitive)
if (output.Captions) {

  // Remove unwanted double quotes
  output.Captions = output.Captions.replace(/"/g, "");

  // Trim extra spaces
  output.Captions = output.Captions.trim();
}

// Fix Hashtags (optional but recommended)
if (output.Hashtags) {

  output.Hashtags = output.Hashtags.replace(/"/g, "").trim();
}

// Merge captions + hashtags properly for LinkedIn
if (output.Captions && output.Hashtags) {
  output.LinkedInText = `${output.Captions}\n\n${output.Hashtags}`;
} else if (output.Captions) {
  output.LinkedInText = output.Captions;
}

return [
  {
    json: output
  }
];
